export default function SplashScreen() {
  const router = useRouter();
  const { isAuthenticated, onboardingComplete } = useAuthStore();

  const gearOpacity = useRef(new Animated.Value(0)).current;
  const gearScale = useRef(new Animated.Value(0.25)).current;
  // Stepped spin: 0→1 represents one full 360° rotation
  const gearSpin = useRef(new Animated.Value(0)).current;

  const circleOpacity = useRef(new Animated.Value(0)).current;
  const circleScale = useRef(new Animated.Value(DOT_SCALE)).current;

  useEffect(() => {
    // Grid spin: 4 × 90° snaps per rotation, each step eases out (mechanical tick feel)
    const spinLoop = Animated.loop(
      Animated.sequence([
        Animated.timing(gearSpin, {
          toValue: 0.25,
          duration: 140,
          easing: Easing.out(Easing.quad),
          useNativeDriver: true,
        }),
        Animated.timing(gearSpin, {
          toValue: 0.5,
          duration: 140,
          easing: Easing.out(Easing.quad),
          useNativeDriver: true,
        }),
        Animated.timing(gearSpin, {
          toValue: 0.75,
          duration: 140,
          easing: Easing.out(Easing.quad),
          useNativeDriver: true,
        }),
        Animated.timing(gearSpin, {
          toValue: 1,
          duration: 140,
          easing: Easing.out(Easing.quad),
          useNativeDriver: true,
        }),
      ]),
    );
    spinLoop.start();

    Animated.sequence([
      // Phase 1 — blank gradient
      Animated.delay(450),

      // Phase 2 — tiny gear fades + pops in
      Animated.parallel([
        Animated.timing(gearOpacity, { toValue: 1, duration: 320, useNativeDriver: true }),
        Animated.timing(gearScale, {
          toValue: 0.38,
          duration: 320,
          easing: Easing.out(Easing.back(1.5)),
          useNativeDriver: true,
        }),
      ]),

      // Phase 3 — gear grows to full size
      Animated.timing(gearScale, {
        toValue: 1,
        duration: 460,
        easing: Easing.out(Easing.cubic),
        useNativeDriver: true,
      }),

      // Phase 4 — gear fades out, circle dot appears
      Animated.parallel([
        Animated.timing(gearOpacity, { toValue: 0, duration: 260, useNativeDriver: true }),
        Animated.timing(circleOpacity, { toValue: 1, duration: 260, useNativeDriver: true }),
      ]),

      // Phase 5 — circle bursts to fill entire screen (expo-out: fast start, smooth finish)
      Animated.timing(circleScale, {
        toValue: 1,
        duration: 680,
        easing: Easing.bezier(0.16, 1, 0.3, 1),
        useNativeDriver: true,
      }),
    ]).start(() => {
      spinLoop.stop();
      setTimeout(() => {
        if (isAuthenticated) {
          router.replace('/(app)/(tabs)/dashboard');
        } else if (onboardingComplete) {
          router.replace('/(auth)/login');
        } else {
          router.replace('/(onboarding)/landing');
        }
      }, 100);
    });

    return () => spinLoop.stop();
  }, []);

  const spinDeg = gearSpin.interpolate({
    inputRange: [0, 1],
    outputRange: ['0deg', '360deg'],
  });

  return (
    <View style={{ flex: 1 }}>
      <StatusBar barStyle="dark-content" translucent backgroundColor="transparent" />

      <LinearGradient
        colors={['#eef0f8', '#e9eaf5', '#e6e3f1']}
        locations={[0, 0.45, 1]}
        style={{ flex: 1 }}
      >
        <View style={{ flex: 1, alignItems: 'center', justifyContent: 'center' }}>
          {/* Gear — phases 2 & 3: scales in + grid-spins */}
          <Animated.View
            style={{
              position: 'absolute',
              opacity: gearOpacity,
              transform: [{ rotate: spinDeg }, { scale: gearScale }],
            }}
          >
            <GearIcon size={88} />
          </Animated.View>

          {/* Circle — phase 4 dot → phase 5 full-screen burst */}
          <Animated.View
            style={{
              position: 'absolute',
              width: CIRCLE_SIZE,
              height: CIRCLE_SIZE,
              borderRadius: CIRCLE_SIZE / 2,
              backgroundColor: FILL_COLOR,
              opacity: circleOpacity,
              transform: [{ scale: circleScale }],
            }}
          />
        </View>
      </LinearGradient>
    </View>
  );
}
